const input = $input.item.json;
const messages = [];

// System message
messages.push({
  role: "system",
  content: `You are an assistant that extracts stock or crypto tickers if they exist.

Return VALID JSON ONLY in this format:
{
  "text": string,
  "ticker": string | null
}

Rules:
- Use standard tickers (AAPL, TSLA, BTCUSDT, SPX)
- If no ticker is clearly mentioned or implied, set ticker to null
- Do not invent tickers
- No markdown code blocks
- No backticks
- Raw JSON only`
});

// Add conversation history if provided
if (Array.isArray(input.history)) {
  for (const msg of input.history) {
    if (msg.role && msg.content) {
      messages.push({ role: msg.role, content: msg.content });
    }
  }
}

// Add current user message
const userMessage = input.message || input.body?.message || "";
if (userMessage.trim()) {
  messages.push({ role: "user", content: userMessage });
}

return { 
  session_id: input.session_id || input.body?.session_id || "default-session", 
  messages 
};

const response = $input.item.json;

// Extract content from Perplexity response
let content = response.choices?.[0]?.message?.content || "";

// Remove markdown code blocks and backticks
content = content
  .replace(/```json\s*/gi, '')
  .replace(/```\s*/g, '')
  .replace(/^`+|`+$/g, '')
  .trim();

// Try to extract JSON if there's extra text
const jsonMatch = content.match(/\{[\s\S]*\}/);
if (jsonMatch) {
  content = jsonMatch[0];
}

// Parse JSON
let parsed;
try {
  parsed = JSON.parse(content);
} catch (error) {
  // One more attempt with line breaks removed
  content = content.replace(/[\r\n]+/g, ' ');
  try {
    parsed = JSON.parse(content);
  } catch (e) {
    throw new Error(`Failed to parse JSON: ${content}`);
  }
}

// Get session_id from previous node
const sessionId = $('Prepare Prompt').item.json.session_id;

// Return clean result
return {
  session_id: sessionId,
  text: parsed.text || "",
  ticker: parsed.ticker || null
};
